  ('heelevel3-d30bcefc-moex-00049', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '以下為去年臺灣國際收支平衡表內各項目的變動：出口800萬美元、進口700萬美元、資本帳淨 流出100萬美元、本國對外國直接投資300萬美元、外國對本國直接投資200萬美元。在不考慮 誤差與遺漏與其他項目的變動下，去年我國央行準備資產變動為何？', '["增加100萬美元", "減少100萬美元", "增加200萬美元", "減少200萬美元 32260 32760"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
