  ('heelevel3-d30bcefc-moex-00051', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '以支出法求算GDP時，下列何者列入政府購買支出？', '["政府公債的利息支出", "失業保險津貼", "政府興建高速公路的支出", "對人民的褔利支出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
